      out.write("		}\n");
      out.write("		else\n");
      out.write("		{\n");
      out.write("			$(this).html('<div align=\"center\"><input class=\"form-control form-control-sm\" type=\"text\" id=\"table_'+title+'\" onkeyup=\"Search(this,'+i+');\" placeholder=\"Search '+title+'\" style=\"width:100px\"/></div>');\n");
      out.write("		}\n");
      out.write("	});\n");
      out.write("	\n");
      out.write("});\n");
      out.write("\n");
      out.write("function Search(obj, indx) \n");
      out.write("{\n");
      out.write("  	var input, filter, table, tr, td, i, txtValue,count=0;\n");
      out.write("  	input = document.getElementById(obj.id);\n");
      out.write("  	\n");
      out.write("  	filter = input.value.toLocaleLowerCase();\n");
      out.write("  	table = document.getElementById(\"example\");\n");
      out.write("  	\n");
      out.write("  	tr = table.getElementsByTagName(\"tr\");\n");
      out.write("  	for (i = 1; i < tr.length; i++) \n");
      out.write("  	{\n");
      out.write("    	td = tr[i].getElementsByTagName(\"td\")[indx];\n");
      out.write("    	if (td) \n");
      out.write("    	{\n");
      out.write("      		txtValue = td.textContent || td.innerText;\n");
      out.write("      		if (txtValue.toLocaleLowerCase().indexOf(filter) > -1) {\n");
      out.write("        		tr[i].style.display = \"\";\n");
      out.write("        		count++;\n");
      out.write("      		} else {\n");
      out.write("      			tr[i].style.display = \"none\";\n");
      out.write("      		}\n");
